import os
import pickle
import json
import time
import hashlib
from functools import wraps
from pathlib import Path
from typing import Any, Optional, Callable
from flask import Flask, request, jsonify

app = Flask(__name__)

class DiskCache:
    def __init__(self, cache_dir: str = 'cache', default_ttl: int = 3600):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(exist_ok=True)
        self.default_ttl = default_ttl
        self._ensure_cache_dir_secure()
    
    def _ensure_cache_dir_secure(self):
        if os.name != 'nt':
            os.chmod(self.cache_dir, 0o700)
    
    def _get_cache_key(self, key: str) -> str:
        safe_key = hashlib.sha256(key.encode('utf-8')).hexdigest()
        return safe_key
    
    def _get_cache_path(self, cache_key: str) -> Path:
        return self.cache_dir / f"{cache_key}.cache"
    
    def set(self, key: str, value: Any, ttl: Optional[int] = None) -> bool:
        try:
            cache_key = self._get_cache_key(key)
            cache_path = self._get_cache_path(cache_key)
            
            expiry_time = time.time() + (ttl if ttl is not None else self.default_ttl)
            
            cache_data = {
                'value': value,
                'expiry': expiry_time,
                'created_at': time.time()
            }
            
            temp_path = cache_path.with_suffix('.tmp')
            with open(temp_path, 'wb') as f:
                pickle.dump(cache_data, f, protocol=pickle.HIGHEST_PROTOCOL)
            
            temp_path.replace(cache_path)
            
            if os.name != 'nt':
                os.chmod(cache_path, 0o600)
            
            return True
        except Exception as e:
            print(f"Cache set error: {e}")
            return False
    
    def get(self, key: str) -> Optional[Any]:
        try:
            cache_key = self._get_cache_key(key)
            cache_path = self._get_cache_path(cache_key)
            
            if not cache_path.exists():
                return None
            
            with open(cache_path, 'rb') as f:
                cache_data = pickle.load(f)
            
            if time.time() > cache_data['expiry']:
                self.delete(key)
                return None
            
            return cache_data['value']
        except Exception as e:
            print(f"Cache get error: {e}")
            return None
    
    def delete(self, key: str) -> bool:
        try:
            cache_key = self._get_cache_key(key)
            cache_path = self._get_cache_path(cache_key)
            
            if cache_path.exists():
                cache_path.unlink()
                return True
            return False
        except Exception as e:
            print(f"Cache delete error: {e}")
            return False
    
    def clear(self) -> int:
        count = 0
        try:
            for cache_file in self.cache_dir.glob('*.cache'):
                cache_file.unlink()
                count += 1
            return count
        except Exception as e:
            print(f"Cache clear error: {e}")
            return count
    
    def cleanup_expired(self) -> int:
        count = 0
        try:
            for cache_file in self.cache_dir.glob('*.cache'):
                try:
                    with open(cache_file, 'rb') as f:
                        cache_data = pickle.load(f)
                    
                    if time.time() > cache_data['expiry']:
                        cache_file.unlink()
                        count += 1
                except Exception:
                    continue
            return count
        except Exception as e:
            print(f"Cache cleanup error: {e}")
            return count
    
    def get_stats(self) -> dict:
        total_files = 0
        total_size = 0
        expired_count = 0
        
        try:
            for cache_file in self.cache_dir.glob('*.cache'):
                total_files += 1
                total_size += cache_file.stat().st_size
                
                try:
                    with open(cache_file, 'rb') as f:
                        cache_data = pickle.load(f)
                    
                    if time.time() > cache_data['expiry']:
                        expired_count += 1
                except Exception:
                    continue
            
            return {
                'total_entries': total_files,
                'total_size_bytes': total_size,
                'expired_entries': expired_count,
                'active_entries': total_files - expired_count
            }
        except Exception as e:
            print(f"Cache stats error: {e}")
            return {
                'total_entries': 0,
                'total_size_bytes': 0,
                'expired_entries': 0,
                'active_entries': 0
            }


cache = DiskCache(cache_dir='api_cache', default_ttl=3600)


def cached(ttl: Optional[int] = None, key_prefix: str = ''):
    def decorator(f: Callable) -> Callable:
        @wraps(f)
        def wrapper(*args, **kwargs):
            cache_key_parts = [key_prefix, f.__name__]
            
            if request:
                cache_key_parts.append(request.path)
                cache_key_parts.append(request.method)
                
                if request.args:
                    sorted_args = sorted(request.args.items())
                    cache_key_parts.append(str(sorted_args))
                
                if request.is_json and request.get_json(silent=True):
                    json_data = request.get_json()
                    cache_key_parts.append(json.dumps(json_data, sort_keys=True))
            
            cache_key_parts.extend([str(arg) for arg in args])
            cache_key_parts.extend([f"{k}:{v}" for k, v in sorted(kwargs.items())])
            
            cache_key = ':'.join(filter(None, cache_key_parts))
            
            cached_value = cache.get(cache_key)
            if cached_value is not None:
                return cached_value
            
            result = f(*args, **kwargs)
            
            cache.set(cache_key, result, ttl=ttl)
            
            return result
        return wrapper
    return decorator


